# Simulate each puzzle carefully

# P1: 2 people, capacity 1
# State: (frozenset on left, frozenset on right, boat_side)
# boat_side: 'L' or 'R'
from collections import deque

def solve_p1():
    # With capacity 1 and both people on left, let's do BFS
    # State: (left_set, right_set, boat_side) — but sets aren't hashable, use frozensets
    initial = (frozenset(['A','B']), frozenset(), 'L')
    goal_left = frozenset()
    goal_right = frozenset(['A','B'])

    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, moves = queue.popleft()
        left, right, boat = state

        if left == goal_left and right == goal_right:
            return moves

        if moves > 20:  # limit
            break

        if boat == 'L':
            # send 1 person to right
            for p in left:
                new_left = left - {p}
                new_right = right | {p}
                new_state = (new_left, new_right, 'R')
                if new_state not in visited:
                    visited.add(new_state)
                    queue.append((new_state, moves + 1))
        else:
            # send 1 person back to left
            for p in right:
                new_left = left | {p}
                new_right = right - {p}
                new_state = (new_left, new_right, 'L')
                if new_state not in visited:
                    visited.add(new_state)
                    queue.append((new_state, moves + 1))

    return None  # No solution found

result_p1 = solve_p1()
print(f"P1 result: {result_p1}")

