# P4: Wolf-Goat-Cabbage
# State: (left_set, right_set, boat_side)
# Items: F (farmer), W (wolf), G (goat), C (cabbage)
# Constraint: W+G alone (no F) = bad; G+C alone (no F) = bad
from collections import deque
from itertools import combinations

def is_valid_bank(bank):
    """Check if a bank configuration is valid (no eating)."""
    # Wolf eats goat if farmer absent
    if 'W' in bank and 'G' in bank and 'F' not in bank:
        return False
    # Goat eats cabbage if farmer absent
    if 'G' in bank and 'C' in bank and 'F' not in bank:
        return False
    return True

def solve_p4():
    all_items = frozenset(['F', 'W', 'G', 'C'])
    initial = (all_items, frozenset(), 'L')
    goal = (frozenset(), all_items, 'R')

    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, moves = queue.popleft()
        left, right, boat = state

        if state[:2] == goal[:2]:
            return moves

        if moves > 20:
            break

        # Farmer must be in boat; can take at most 1 other item
        if boat == 'L' and 'F' in left:
            # Farmer goes alone or with 1 item
            companions = left - {'F'}
            groups = [frozenset({'F'})] + [frozenset({'F', x}) for x in companions]
            for group in groups:
                new_left = left - group
                new_right = right | group
                if is_valid_bank(new_left) and is_valid_bank(new_right):
                    new_state = (new_left, new_right, 'R')
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, moves + 1))
        elif boat == 'R' and 'F' in right:
            companions = right - {'F'}
            groups = [frozenset({'F'})] + [frozenset({'F', x}) for x in companions]
            for group in groups:
                new_right = right - group
                new_left = left | group
                if is_valid_bank(new_left) and is_valid_bank(new_right):
                    new_state = (new_left, new_right, 'L')
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, moves + 1))

    return None

result_p4 = solve_p4()
print(f"P4 result: {result_p4}")

# P5: Missionaries and Cannibals
# State: (m_left, c_left, boat_side)
# Constraint: if m_left > 0 then m_left >= c_left; if m_right > 0 then m_right >= c_right
def is_valid_mc(m_left, c_left):
    m_right = 3 - m_left
    c_right = 3 - c_left
    if m_left > 0 and m_left < c_left:
        return False
    if m_right > 0 and m_right < c_right:
        return False
    return True

def solve_p5():
    initial = (3, 3, 'L')
    goal = (0, 0, 'R')

    queue = deque([(initial, 0)])
    visited = {initial}

    while queue:
        state, moves = queue.popleft()
        ml, cl, boat = state

        if (ml, cl) == (0, 0) and boat == 'R':
            return moves

        if moves > 20:
            break

        capacity = 2
        if boat == 'L':
            # Send 1 or 2 people to right
            for dm in range(0, capacity+1):
                for dc in range(0, capacity+1 - dm):
                    if dm + dc == 0 or dm + dc > capacity:
                        continue
                    if dm > ml or dc > cl:
                        continue
                    new_ml = ml - dm
                    new_cl = cl - dc
                    if is_valid_mc(new_ml, new_cl):
                        new_state = (new_ml, new_cl, 'R')
                        if new_state not in visited:
                            visited.add(new_state)
                            queue.append((new_state, moves + 1))
        else:
            mr = 3 - ml
            cr = 3 - cl
            for dm in range(0, capacity+1):
                for dc in range(0, capacity+1 - dm):
                    if dm + dc == 0 or dm + dc > capacity:
                        continue
                    if dm > mr or dc > cr:
                        continue
                    new_ml = ml + dm
                    new_cl = cl + dc
                    if is_valid_mc(new_ml, new_cl):
                        new_state = (new_ml, new_cl, 'L')
                        if new_state not in visited:
                            visited.add(new_state)
                            queue.append((new_state, moves + 1))

    return None

result_p5 = solve_p5()
print(f"P5 result: {result_p5}")

